{
  "name": "AudioAnalista AI",
  "description": "Herramienta inteligente para transcribir y analizar reuniones a partir de archivos de audio, generando resúmenes, ideas clave y acuerdos."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AnalysisResult {
  executiveSummary: string;
  keyIdeas: string[];
  futureAgreements: string[];
  participants: string[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
}

export interface ProcessingError {
  message: string;
  details?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string suitable for the Gemini API.
 */
const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:audio/mp3;base64,")
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Analyzes the audio file using Gemini Flash.
 */
export const analyzeAudioFile = async (file: File): Promise<AnalysisResult> => {
  try {
    const audioPart = await fileToGenerativePart(file);

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          audioPart,
          {
            text: `Por favor, analiza este archivo de audio de una reunión o conversación. 
            Actúa como un secretario experto y extrae la siguiente información en español estructurado:
            1. Un resumen ejecutivo conciso.
            2. Las ideas principales discutidas.
            3. Los acuerdos futuros o tareas pendientes (Next steps).
            4. Una lista de los probables participantes (identificados por voz o contexto).

            Asegúrate de capturar los matices importantes.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: {
              type: Type.STRING,
              description: "Un resumen ejecutivo completo de la grabación.",
            },
            keyIdeas: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de las ideas o temas principales discutidos.",
            },
            futureAgreements: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de acuerdos, tareas o pasos a seguir acordados.",
            },
            participants: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Nombres o roles de los participantes identificados.",
            },
          },
          required: ["executiveSummary", "keyIdeas", "futureAgreements", "participants"],
        },
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing audio:", error);
    throw error;
  }
};

import React, { useCallback, useState } from 'react';
import { UploadCloud, FileAudio, AlertCircle } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
  disabled?: boolean;
}

const MAX_SIZE_MB = 15; // Gemini has limits, keep it safe for client-side encoding

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, disabled }) => {
  const [dragActive, setDragActive] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const validateAndPassFile = (file: File) => {
    setError(null);
    if (!file.type.startsWith('audio/')) {
      setError("Por favor sube un archivo de audio válido (MP3, WAV, M4A, etc).");
      return;
    }
    if (file.size > MAX_SIZE_MB * 1024 * 1024) {
      setError(`El archivo es demasiado grande. El límite para esta demo es ${MAX_SIZE_MB}MB.`);
      return;
    }
    onFileSelect(file);
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0] && !disabled) {
      validateAndPassFile(e.dataTransfer.files[0]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [disabled, onFileSelect]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0] && !disabled) {
      validateAndPassFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div
        className={`relative flex flex-col items-center justify-center w-full h-64 border-2 border-dashed rounded-2xl transition-all duration-300 ease-in-out
          ${dragActive ? "border-blue-500 bg-blue-50 scale-[1.01]" : "border-slate-300 bg-white hover:bg-slate-50"}
          ${disabled ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}
        `}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input
          id="dropzone-file"
          type="file"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
          onChange={handleChange}
          accept="audio/*"
          disabled={disabled}
        />

        <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
          <div className={`p-4 rounded-full mb-4 ${dragActive ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-500'}`}>
            {dragActive ? <UploadCloud size={40} /> : <FileAudio size={40} />}
          </div>
          <p className="mb-2 text-xl font-semibold text-slate-700">
            {dragActive ? "Suelta el archivo aquí" : "Arrastra y suelta tu audio"}
          </p>
          <p className="text-sm text-slate-500 mb-4">
            MP3, WAV, AAC, M4A (Max {MAX_SIZE_MB}MB)
          </p>
          <button 
            type="button"
            className="px-6 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:ring-4 focus:outline-none focus:ring-blue-300 transition-colors pointer-events-none"
          >
            Seleccionar Archivo
          </button>
        </div>
      </div>

      {error && (
        <div className="mt-4 p-4 text-red-700 bg-red-50 rounded-lg flex items-center gap-2 animate-fadeIn">
          <AlertCircle size={20} />
          <span className="text-sm font-medium">{error}</span>
        </div>
      )}
    </div>
  );
};

import React from 'react';
