import React, { useState } from 'react';
import { FileUpload } from './components/FileUpload';
import { ResultsDisplay } from './components/ResultsDisplay';
import { analyzeAudioFile } from './services/geminiService';
import { AppStatus, AnalysisResult } from './types';
import { Loader2, Mic, ChevronLeft } from 'lucide-react';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [fileName, setFileName] = useState<string>("");

  const handleFileSelect = async (file: File) => {
    setStatus(AppStatus.ANALYZING);
    setError(null);
    setFileName(file.name);

    try {
      const data = await analyzeAudioFile(file);
      setResult(data);
      setStatus(AppStatus.SUCCESS);
    } catch (err) {
      console.error(err);
      setError("Hubo un error al procesar el audio. Asegúrate de que el archivo no esté dañado y que la API key sea válida.");
      setStatus(AppStatus.ERROR);
    }
  };

  const handleReset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setError(null);
    setFileName("");
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Mic size={20} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">AudioAnalista AI</h1>
          </div>
          {status === AppStatus.SUCCESS && (
            <button 
              onClick={handleReset}
              className="flex items-center gap-1 text-sm font-medium text-slate-600 hover:text-slate-900 transition-colors"
            >
              <ChevronLeft size={16} />
              Analizar otro archivo
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-12">

        {/* Intro Text (Only show when IDLE) */}
        {status === AppStatus.IDLE && (
          <div className="text-center mb-12">
            <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
              Transforma tus reuniones en <span className="text-blue-600">información accionable</span>
            </h2>
            <p className="text-lg text-slate-600 max-w-2xl mx-auto">
              Sube tu grabación de audio y nuestra IA extraerá automáticamente el resumen, 
              los puntos clave, acuerdos y participantes en segundos.
            </p>
          </div>
        )}

        {/* State Management */}
        {status === AppStatus.IDLE && (
          <div className="fade-in">
            <FileUpload onFileSelect={handleFileSelect} />
          </div>
        )}

        {status === AppStatus.ANALYZING && (
          <div className="flex flex-col items-center justify-center py-20 animate-fadeIn">
            <div className="relative">
              <div className="absolute inset-0 bg-blue-100 rounded-full animate-ping opacity-75"></div>
              <div className="relative bg-white p-4 rounded-full shadow-xl border border-blue-100">
                <Loader2 size={48} className="text-blue-600 animate-spin" />
              </div>
            </div>
            <h3 className="mt-8 text-2xl font-semibold text-slate-900">Analizando Audio...</h3>
            <p className="mt-2 text-slate-500">Esto puede tomar unos momentos dependiendo de la duración del archivo.</p>
            <div className="mt-4 px-4 py-2 bg-slate-100 rounded-md text-sm text-slate-600 font-mono">
              Procesando: {fileName}
            </div>
          </div>
        )}

        {status === AppStatus.ERROR && (
          <div className="max-w-lg mx-auto text-center py-12 animate-fadeIn">
            <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
              <Mic size={32} className="rotate-45" />
            </div>
            <h3 className="text-xl font-bold text-slate-900 mb-2">Error en el análisis</h3>
            <p className="text-slate-600 mb-8">{error}</p>
            <button 
              onClick={handleReset}
              className="px-6 py-3 bg-slate-900 text-white rounded-lg font-medium hover:bg-slate-800 transition-colors shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all"
            >
              Intentar de nuevo
            </button>
          </div>
        )}

        {status === AppStatus.SUCCESS && result && (
          <ResultsDisplay data={result} />
        )}

      </main>

      {/* Simple Footer */}
      <footer className="border-t border-slate-200 mt-auto py-8 bg-white fixed bottom-0 w-full hidden lg:block">
        <div className="max-w-5xl mx-auto px-4 text-center text-slate-400 text-sm">
          <p>Powered by Google Gemini 2.5 Flash • Procesa audio nativamente</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

