import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string suitable for the Gemini API (Inline).
 * Used for smaller files to reduce latency.
 */
const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Uploads a large file to Gemini Files API and waits for it to be processed.
 */
const uploadLargeFile = async (file: File): Promise<{ fileData: { fileUri: string; mimeType: string } }> => {
  console.log("Iniciando carga de archivo grande a Gemini Files API...");

  // 1. Upload the file
  const uploadResponse = await ai.files.upload({
    file: file,
    config: { 
      displayName: file.name,
      mimeType: file.type 
    }
  });

  const fileName = uploadResponse.file.name;
  console.log(`Archivo subido: ${fileName}. Esperando procesamiento...`);

  // 2. Poll until the file is active
  let fileInfo = await ai.files.get({ name: fileName });

  while (fileInfo.file.state === 'PROCESSING') {
    await new Promise(resolve => setTimeout(resolve, 2000)); // Wait 2 seconds
    fileInfo = await ai.files.get({ name: fileName });
    console.log(`Estado del archivo: ${fileInfo.file.state}`);
  }

  if (fileInfo.file.state === 'FAILED') {
    throw new Error("El procesamiento del audio falló en los servidores de Google.");
  }

  return {
    fileData: {
      fileUri: fileInfo.file.uri,
      mimeType: fileInfo.file.mimeType
    }
  };
};

/**
 * Analyzes the audio file using Gemini Flash.
 * Automatically switches strategy based on file size.
 */
export const analyzeAudioFile = async (file: File): Promise<AnalysisResult> => {
  try {
    const INLINE_LIMIT_BYTES = 20 * 1024 * 1024; // 20MB
    let audioPart;

    // Strategy selection: Inline for speed on small files, Files API for heavy lifting
    if (file.size < INLINE_LIMIT_BYTES) {
      console.log("Modo: Inline (Archivo pequeño)");
      audioPart = await fileToGenerativePart(file);
    } else {
      console.log("Modo: Files API (Archivo grande)");
      audioPart = await uploadLargeFile(file);
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          audioPart,
          {
            text: `Por favor, analiza este archivo de audio de una reunión o conversación. 
            Actúa como un secretario experto y extrae la siguiente información en español estructurado:
            1. Un resumen ejecutivo conciso.
            2. Las ideas principales discutidas.
            3. Los acuerdos futuros o tareas pendientes (Next steps).
            4. Una lista de los probables participantes (identificados por voz o contexto).

            Asegúrate de capturar los matices importantes.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            executiveSummary: {
              type: Type.STRING,
              description: "Un resumen ejecutivo completo de la grabación.",
            },
            keyIdeas: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de las ideas o temas principales discutidos.",
            },
            futureAgreements: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de acuerdos, tareas o pasos a seguir acordados.",
            },
            participants: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Nombres o roles de los participantes identificados.",
            },
          },
          required: ["executiveSummary", "keyIdeas", "futureAgreements", "participants"],
        },
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response text received from Gemini.");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing audio:", error);
    throw error;
  }
};

import React, { useCallback, useState } from 'react';
import { UploadCloud, FileAudio, AlertCircle } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
  disabled?: boolean;
  compact?: boolean;
}

const MAX_SIZE_MB = 500; // Increased limit for Files API support

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, disabled, compact }) => {
  const [dragActive, setDragActive] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const validateAndPassFile = (file: File) => {
    setError(null);
    if (!file.type.startsWith('audio/')) {
      setError("Por favor sube un archivo de audio válido (MP3, WAV, M4A, etc).");
      return;
    }
    if (file.size > MAX_SIZE_MB * 1024 * 1024) {
      setError(`El archivo supera el límite de ${MAX_SIZE_MB}MB.`);
      return;
    }
    onFileSelect(file);
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0] && !disabled) {
      validateAndPassFile(e.dataTransfer.files[0]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [disabled, onFileSelect]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0] && !disabled) {
      validateAndPassFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full h-full flex flex-col">
      <div
        className={`relative flex flex-col items-center justify-center w-full border-2 border-dashed rounded-xl transition-all duration-300 ease-in-out flex-grow min-h-[250px]
          ${dragActive ? "border-indigo-500 bg-indigo-50 scale-[1.01]" : "border-slate-300 bg-white hover:bg-slate-50"}
          ${disabled ? "opacity-50 cursor-not-allowed" : "cursor-pointer"}
        `}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input
          id="dropzone-file"
          type="file"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed z-10"
          onChange={handleChange}
          accept="audio/*"
          disabled={disabled}
        />

        <div className="flex flex-col items-center justify-center p-6 text-center z-0">
          <div className={`p-4 rounded-full mb-4 shadow-sm ${dragActive ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-500'}`}>
            {dragActive ? <UploadCloud size={32} /> : <FileAudio size={32} />}
          </div>
          <p className="mb-2 text-lg font-semibold text-slate-800">
            {dragActive ? "Suelta el audio" : "Subir Audio"}
          </p>
          <p className="text-xs text-slate-500 mb-4 px-4 leading-relaxed">
            Arrastra o haz clic para buscar. <br/>
            Soporta MP3, WAV, M4A.<br/>
            <span className="font-medium text-slate-600">Máx {MAX_SIZE_MB}MB</span>
          </p>
          <div 
            className="px-4 py-2 text-xs font-medium text-white bg-slate-900 rounded-md shadow-md"
          >
            Explorar Archivos
          </div>
        </div>
      </div>

      {error && (
        <div className="mt-4 p-3 text-red-700 bg-red-50 border border-red-100 rounded-lg flex items-start gap-2 animate-fadeIn text-sm">
          <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
          <span>{error}</span>
        </div>
      )}
    </div>
  );
};

